const API_KEY = process.env.REACT_APP_ANTHROPIC_API_KEY;
const MODEL = 'claude-sonnet-4-20250514';
const API_URL = 'https://api.anthropic.com/v1/messages';

if (!API_KEY) {
  console.error(
    '[claudeAPI] REACT_APP_ANTHROPIC_API_KEY is undefined. ' +
    'Make sure .env exists in the project root and the dev server was restarted after it was created.'
  );
}

const SYSTEM_PROMPT =
  'You are a matching assistant for RePlay LA, connecting post-LA28 Olympics surplus materials to LA community organizations. Return matches as JSON with this shape: { matches: [{ material, reason, fit_score }], summary }';

async function callClaude(messages, system = SYSTEM_PROMPT) {
  const response = await fetch(API_URL, {
    method: 'POST',
    headers: {
      'Content-Type': 'application/json',
      'x-api-key': API_KEY,
      'anthropic-version': '2023-06-01',
      'anthropic-dangerous-direct-browser-access': 'true',
    },
    body: JSON.stringify({
      model: MODEL,
      max_tokens: 1024,
      system,
      messages,
    }),
  });

  if (!response.ok) {
    const error = await response.json().catch(() => ({}));
    throw new Error(error.error?.message || `API error ${response.status}`);
  }

  const data = await response.json();
  return data.content[0].text;
}

export async function chat(messages) {
  return callClaude(messages);
}

export async function getMatches(orgProfile, availableMaterials) {
  const userMessage = `Organization profile:\n${JSON.stringify(orgProfile, null, 2)}\n\nAvailable materials:\n${JSON.stringify(availableMaterials, null, 2)}\n\nReturn only valid JSON with the shape { matches: [{ material, reason, fit_score }], summary }.`;

  const text = await callClaude([{ role: 'user', content: userMessage }]);

  const jsonMatch = text.match(/\{[\s\S]*\}/);
  if (!jsonMatch) throw new Error('No JSON found in response');
  return JSON.parse(jsonMatch[0]);
}
